// src/Login.js
import React, { useState } from "react";
import axios from "axios";
import { useAuth } from "./context/AuthContext";

function Login() {
  const [usuario, setUsuario] = useState("");
  const [senha, setSenha] = useState("");
  const [mensagem, setMensagem] = useState("");
  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post("/api/login", { usuario, senha });
      login({ role: res.data.role, token: res.data.token });
      // O redirecionamento acontece via AppRoutes/ProtectedRoute
    } catch (error) {
      setMensagem("Usuário ou senha inválidos!");
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="max-w-sm mx-auto p-6 bg-white rounded-2xl shadow space-y-4 mt-12"
    >
      <h2 className="text-2xl font-bold mb-4">Login</h2>
      <input
        className="w-full border rounded px-3 py-2"
        placeholder="Usuário"
        value={usuario}
        onChange={(e) => setUsuario(e.target.value)}
        required
      />
      <input
        className="w-full border rounded px-3 py-2"
        placeholder="Senha"
        value={senha}
        onChange={(e) => setSenha(e.target.value)}
        type="password"
        required
      />
      <button
        className="w-full bg-[#3172C0] text-white py-2 rounded-full font-semibold"
        type="submit"
      >
        Entrar
      </button>
      {mensagem && <p className="text-red-600">{mensagem}</p>}
    </form>
  );
}

export default Login;
